-- MoneyMatters seed data
-- Generated: 2026-04-04
-- This script reseeds the database with corrected portfolio data.
-- Run: sqlite3 money-matters.db < seed.sql
--
-- NOTE: currentPrice / lastUpdated are NOT seeded — they are
--       populated automatically by the price-update scheduler.

PRAGMA foreign_keys = OFF;

BEGIN TRANSACTION;

-- Clear existing data (order matters for FK)
DELETE FROM realized_gains;
DELETE FROM benchmark_prices;
DELETE FROM price_history;
DELETE FROM portfolio_snapshots;
DELETE FROM transactions;
DELETE FROM asset_tags;
DELETE FROM holdings;
DELETE FROM assets;
DELETE FROM tags;
DELETE FROM benchmarks;

